<?php
declare(strict_types=1);
require_once __DIR__ . '/_intelligence.php';
$method=strtoupper($_SERVER['REQUEST_METHOD']??'GET');$user=mg_require_permission($method==='GET'?'intelligence.dashboard.view':'intelligence.alerts.manage');$pdo=mg_db();
if($method==='GET'){$stmt=$pdo->prepare('SELECT public_id,name,metric_key,comparison,threshold_value,lookback_days,status,channels_json,created_at,updated_at FROM demand_alert_rules WHERE merchant_user_id=? ORDER BY updated_at DESC');$stmt->execute([(int)$user['id']]);mg_ok(['rules'=>$stmt->fetchAll()]);}
if($method!=='POST')mg_fail('Method not allowed.',405);$input=mg_input();mg_require_csrf_for_write($input);$ruleId=trim((string)($input['rule_id']??''));$name=trim((string)($input['name']??''));$metric=trim((string)($input['metric_key']??''));$comparison=trim((string)($input['comparison']??'gt'));$threshold=(float)($input['threshold_value']??0);$lookback=max(1,min(365,(int)($input['lookback_days']??7)));$status=trim((string)($input['status']??'active'));$metrics=['items_issued','issued_value_cents','claims','redemptions','open_rate','claim_rate','redemption_rate'];if($name===''||!in_array($metric,$metrics,true)||!in_array($comparison,['gt','gte','lt','lte','change_gt','change_lt'],true)||!in_array($status,['active','paused','archived'],true))mg_fail('Invalid alert rule.',422);$channels=mg_intelligence_json($input['channels']??null,32768);
if($ruleId===''){$ruleId=mg_intelligence_uuid();$pdo->prepare('INSERT INTO demand_alert_rules (public_id,merchant_user_id,name,metric_key,comparison,threshold_value,lookback_days,status,channels_json,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,NOW(),NOW())')->execute([$ruleId,(int)$user['id'],$name,$metric,$comparison,$threshold,$lookback,$status,$channels]);}else{$stmt=$pdo->prepare('UPDATE demand_alert_rules SET name=?,metric_key=?,comparison=?,threshold_value=?,lookback_days=?,status=?,channels_json=?,updated_at=NOW() WHERE public_id=? AND merchant_user_id=?');$stmt->execute([$name,$metric,$comparison,$threshold,$lookback,$status,$channels,$ruleId,(int)$user['id']]);if($stmt->rowCount()===0)mg_fail('Alert rule not found.',404);}mg_ok(['rule_id'=>$ruleId,'status'=>$status],'Alert rule saved.',201);
